type SpringPositionOptions =
  | {
      /** The difference to the target position. If `from` and `to` are provided, this is  as to - from`. */
      diff: number;
      from?: number;
      to?: never;
      /** To use this mode, `from` and `to` must be provided. */
      preventOvershoot?: never;
    }
  | {
      diff?: never;
      from: number;
      to: number;
      /** Whether to prevent overshooting the target position. */
      preventOvershoot?: boolean;
    };

type SpringOptions = {
  stiffness?: number;
  damping?: number;
  mass?: number;
  timeStep?: number;
};

type InitialSpringOptions = SpringOptions & {
  initialVelocity?: number;
  /** Whether to prevent overshooting the target position. */
  preventOvershoot?: boolean;
};

type UpdateSpringOptions = SpringPositionOptions & SpringOptions;

/**
 * Makes a basic spring physics simulation.
 * Calculates the next velocity based on the difference to the target and current velocity.
 * @param base Spring options. Note that these can be overridden in the `update` method.
 * @returns An object with an `update` method that takes spring options and returns the next velocity.
 */
export function spring(base?: InitialSpringOptions) {
  let velocity = base?.initialVelocity ?? 0;

  function update({
    from,
    to,
    diff,
    preventOvershoot = base?.preventOvershoot ?? true,
    stiffness = base?.stiffness ?? 0.1,
    damping = base?.damping ?? 0.8,
    mass = base?.mass ?? 1,
    timeStep = base?.timeStep ?? 1,
  }: UpdateSpringOptions) {
    const hasFromTo = from !== undefined && to !== undefined;
    from ??= 0;

    if (diff === undefined) {
      if (!hasFromTo) throw new Error('Either diff or from/to must be provided');
      diff = to - from;
    }

    const restoringForce = diff * stiffness;
    const dragForce = velocity * damping;
    const netForce = restoringForce - dragForce;
    const acceleration = netForce / mass;
    const dv = acceleration * timeStep;
    velocity += dv;

    let dx = velocity * timeStep;
    if (preventOvershoot && hasFromTo) {
      const direction = Math.sign(dx);

      if (direction === Math.sign(diff)) {
        const clamped = Math.min(Math.abs(dx), Math.abs(diff)) * direction;

        if (clamped !== dx) {
          velocity = clamped / timeStep; // keep velocity consistent
          dx = clamped;
        }
      }
    }

    const position = from + dx;
    const settled = Math.abs(diff) < 0.001 && Math.abs(velocity) < 0.001;

    return { acceleration, velocity, position, settled };
  }

  function reset(opts?: InitialSpringOptions) {
    velocity = opts?.initialVelocity ?? base?.initialVelocity ?? 0;
    base = { ...base, ...opts };
  }

  function getVelocity() {
    return velocity;
  }

  return { update, reset, getVelocity };
}
